async function retry<T>(fn: () => Promise<T>, attempts: number, delayMs = 0): Promise<T> {
  for (let i = 0; i < attempts; i++) {
    try { return await fn() }
    catch (err) {
      if (i === attempts - 1) throw err
      if (delayMs) await new Promise(r => setTimeout(r, delayMs))
    }
  }
  throw new Error('unreachable')
}
